tool.command:
@CMD_UNZIP_ZARR@
mkdir -p output_dir &&
echo "Resolving patch conflicts" && sopa resolve #if $method.method_name == 'cellpose' cellpose #for $cache in str($method.cache_dir_name).split(',') --cache-dir-name '$cache' #end for #else if $method.method_name == 'stardist' stardist #for $cache in str($method.cache_dir_name).split(',') --cache-dir-name '$cache' #end for #else if $method.method_name == 'baysor' baysor #if str($method.gene_column) != '' --gene-column $method.gene_column #end if --min-area $method.min_area #else if $method.method_name == 'comseg' comseg #if str($method.gene_column) != '' --gene-column $method.gene_column #end if --min-area $method.min_area #end if input/spatialdata.zarr ## Move to output directory && mv "input/spatialdata.zarr" output_dir/ &&
@CMD_ZIP_ZARR@
